const fd = await foundry.applications.api.DialogV2.wait({
  window: { title: "Blessure critique" },
  content: `
    <div class="form-group"><label>Table</label>
      <select name="table"><option value="perso">Personnage</option><option value="veh">Véhicule / vaisseau</option></select></div>
    <div class="form-group"><label>Critiques déjà subis (+10 chacun)</label><input type="number" name="prev" value="0" min="0"/></div>
    <div class="form-group"><label>Bonus (Sanguinaire ×10, talents…)</label><input type="number" name="bonus" value="0"/></div>`,
  buttons: [{ action: "ok", label: "Tirer", default: true,
    callback: (event, button) => new (foundry.applications.ux?.FormDataExtended ?? FormDataExtended)(button.form).object }],
});
if (!fd) return;
const name = fd.table === "veh" ? "🔥 Avaries critiques — véhicules (d100)" : "🩸 Blessures critiques (d100)";
const table = game.tables.getName(name);
if (!table) return ui.notifications.error(`Table introuvable : ${name}`);
const mod = Number(fd.prev) * 10 + Number(fd.bonus);
const roll = new Roll(`1d100 + ${mod}`);
await table.draw({ roll });
